                     <span className="font-semibold">{truck.plate}</span>
                     <span className="opacity-80 text-[10px]">{truck.model}</span>
                     <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-2 h-2 bg-slate-900 rotate-45"></div>
